INSERT INTO `insights` (`id`, `id_plan`, `status_id`, `id_user`, `date`, `icon`, `title`, `description`, `created_at`, `updated_at`, `deleted_at`) VALUES
(10, 1, 1, 16, '2024-10-13', '21', 'Semillas', 'Se registra afecciones significativas en el poder germinativo de semillas de Soja. Los precios de las semillas de soja, girasol y sorgo registran subas en los ultimos meses y se notaron bajas en los precios de semillas de maíz.', '2024-11-14 02:43:15', '2024-11-14 02:43:15', NULL),
(11, 1, 1, 16, '2024-10-13', '29', 'Fertilizantes', 'Hoy el consumo de fertilizantes  está limitado fundamentalmente por la limitación de los márgenes agropecuarios, afectados especialmente por los derechos de exportación', '2024-11-14 02:43:15', '2024-11-14 02:43:15', NULL),
(12, 1, 1, 16, '2024-10-13', NULL, 'Clima', 'Las lluvias de octubre salvaron de otra campaña gruesa regular/mala (en algunas regiones hubiese sido la tercer o cuarta campaña regular)', '2024-11-14 02:43:15', '2024-11-14 02:43:15', NULL),
(13, 1, 1, 16, '2024-10-13', '35', 'Venta de insumos', 'Ventas de insumos, siembras y pagos retrasados. En algunos segmentos las ventas son poco más de la mitad del año pasado a la misma altura de la campaña', '2024-11-14 02:43:15', '2024-11-14 02:43:15', NULL),
(14, 1, 1, 16, '2024-10-13', '27', 'Arrendamientos', 'Para el 76 % de los productores el pago de los arrendamientos representa el 40 % o más de sus costos totales', '2024-11-14 02:43:15', '2024-11-14 02:43:15', NULL),
(15, 1, 1, 16, '2024-10-13', '14', 'Inversión ', 'Los productores que van a invertir esta campaña lo haran en maquinarias grandes (42%), hacienda vacuna (33%), tierra (23%) y otras maquinarias', '2024-11-14 02:43:15', '2024-11-14 02:43:15', NULL),
(16, 1, 1, 16, '2024-10-13', '24', 'Chicharrita', 'A pesar que la chicharrita registra una baja en incidencia, todos los productores le tienen respeto al vector y en el norte estarán sembrando significativamente menos maíz tardío y en la zona sur prácticamente no se verá afectada la superficie de maíz. ', '2024-11-14 02:43:15', '2024-11-14 02:43:15', NULL),
(17, 1, 1, 16, '2024-10-13', '21', 'Ventas de Granos', 'Mejoró el ritmo de ventas de granos de parte del productor', '2024-11-14 02:43:15', '2024-11-14 02:43:15', NULL),
(18, 1, 1, 16, '2024-10-13', '23', 'Relación Insumo:Producto', 'Buenas relación Insumo producto para fertilizantes Nitrogenados y algunos herbicidas', '2024-11-14 02:43:15', '2024-11-14 02:43:15', NULL),
(19, 1, 1, 16, '2024-11-01', '27', 'Alquileres', 'Alquileres sostenidos a pesar de margenes bajos. Hay zonas que incluso subieron levemente los valores de alquiler traccionado por siembras de maní con buen margen.', '2024-12-10 01:44:54', '2024-12-10 01:44:54', NULL),
(20, 1, 1, 16, '2024-11-01', '25', 'Valor de la tierra', 'Aumenta el valor de las tierras, principalmente en regiones marginales (+10%) y aumenta la carga de vacunos por hectarea.', '2024-12-10 01:44:54', '2024-12-10 01:44:54', NULL),
(21, 1, 1, 16, '2024-11-30', '33', 'Fertilización en Argentina', 'Argentina se encuentra entre los países que feriliza menos por hectárea, y esto lleva a tener rindes por hectárea menores a países de la region con suelos más pobres', '2024-12-10 01:44:54', '2024-12-10 01:44:54', NULL),
(22, 1, 1, 16, '2024-11-01', '21', 'Ventas de Granos', 'Mejoró el ritmo de ventas de granos de parte del productor', '2024-12-10 01:44:54', '2024-12-10 01:44:54', NULL),
(23, 1, 1, 16, '2024-11-01', '42', 'Buen clima', 'Dado que la niña no fue intensa y casi no tuvo efectos, se prevee que el maíz tardío puede tener una superficie muy superior a la estimada hace unos meses.', '2024-12-10 01:44:54', '2024-12-10 01:44:54', NULL),
(24, 1, 1, 16, '2024-11-30', '27', 'Relación Insumo:Producto', 'Buenas relación Insumo producto para fertilizantes Nitrogenados y herbicidas', '2024-12-10 01:44:54', '2024-12-10 01:44:54', NULL),
(25, 1, 1, 16, '2024-11-01', '17', 'Derechos de exportador', 'La recaudación por derechos de exportación se estima que terminará este año en U$S 5.500 millones. Para el 2025, por la mayor cosecha implicaría otro salto del 48%, hasta más de U$S 8.000 millones.', '2024-12-10 01:44:54', '2024-12-10 01:44:54', NULL),
(26, 1, 1, 16, '2024-11-01', '6', 'Ganadería', 'Los precios de la ganadería mejoraron a la suba y se cree que con esto puede aumentar la cantidad de cabezas en retencion', '2024-12-10 01:44:54', '2024-12-10 01:44:54', NULL),
(27, 1, 1, 16, '2024-11-30', '30', 'Compra insumos', 'Los productores frenan las compras de insumos, esperando a la baja del impuesto país, aunque se sabe que mucho de la baja impositiva ya está priceado y no se cree que pueda bajar mucho los valores de los insumos', '2024-12-10 01:44:54', '2024-12-10 01:44:54', NULL),
(28, 1, 1, 16, '2024-11-30', '14', 'Venta de insumos', 'Avance de ventas de insumos muy demorados (35 % de avance de venta de semillas de maíz, en promedio todos los insumos vienen un 40 % demorado versus campaña previa)', '2024-12-10 01:44:54', '2024-12-10 01:44:54', NULL),
(29, 1, 1, 16, '2024-12-30', '37', 'Impuesto Pais', 'Se eliminó finalmente el impuesto país. Se estima que el impacto del precio en la urea será de 30 USD y 46 USD en MAP', '2025-01-03 23:54:45', '2025-01-03 23:54:45', NULL),
(30, 1, 1, 16, '2024-12-30', '8', 'Maíz', 'Sigue aumentando las estimaciones de área sembrada por maíz dada la baja población de chicharrita en centro y sur del país y por las lluvias que se dieron hasta mediados de diciembre.', '2025-01-03 23:54:45', '2025-01-03 23:54:45', NULL),
(31, 1, 1, 16, '2024-12-30', '35', 'Venta de insumos', 'Avance de ventas de insumos muy demorados. Baja demanda por baja en las lluvias, expectativa del impuesto país y baja de precios de algunos granos (el mas retrasado son las semillas de maíz, y los fertilizantes fosfatados)', '2025-01-03 23:54:45', '2025-01-03 23:54:45', NULL),
(32, 1, 1, 16, '2024-12-30', '29', 'Importacion', 'Se calcula que al momento se lleva importado 1 millon de toneladas de Urea  y 765 K tn de MAP, con bajas de 6 % Vs el mes anterior en los precios de la urea', '2025-01-03 23:54:45', '2025-01-03 23:54:45', NULL),
(33, 1, 1, 16, '2024-12-30', '42', 'Clima', 'Se frenaron las lluvias en el norte y Sudoeste de Buenos Aires, lo cual podría afectar a los rindes.', '2025-01-03 23:54:45', '2025-01-03 23:54:45', NULL),
(34, 1, 1, 16, '2024-12-30', '29', 'Glifosato', 'Los precios de algunos herbicidas como glifosato y 2,4D siguen bajando (entre 40 % y 80 desde máximos de 2022)', '2025-01-03 23:54:45', '2025-01-03 23:54:45', NULL),
(35, 1, 1, 16, '2024-12-30', '27', 'Alquileres', 'Los precios de los alquileres se mantienen estables y  en algunos casos incluso suben levemente  en algunas zonas.', '2025-01-03 23:54:45', '2025-01-03 23:54:45', NULL),
(36, 1, 1, 16, '2024-12-30', '9', 'Ganadería', 'Los dos escenarios más probables para la ganadería argentina en 2025 comprenden una caída de la faena bovina del 5% al 10% respecto de 2024, el cual sería compensado parcialmente con un crecimiento del peso medio de faena.', '2025-01-03 23:54:45', '2025-01-03 23:54:45', NULL),
(37, 1, 1, 16, '2024-12-30', NULL, 'Sitiuación financiera', 'Default de Los Grobo y Agrofina: incumplirán pagarés por US$10 millones hasta marzo. Había deudas en USD de Obligaciones negociables y en $ AR de pagarés entre otros.', '2025-01-03 23:54:45', '2025-01-03 23:54:45', NULL),
(38, 1, 1, 16, '2024-12-30', '18', 'Fertilización en Argentina', 'Argentina se encuentra entre los países que fertiliza menos por hectárea, y esto lleva a tener rindes por hectárea menores a países de la región con suelos más pobres', '2025-01-03 23:54:45', '2025-01-03 23:54:45', NULL),
(52, 1, 1, 16, '2025-01-31', '42', 'Sequía 2024', 'La sequía en 2024 podría causar pérdidas económicas en más del 50% de los agricultores y ganaderos. Estos pueden ser indemnizados con hasta el 80% del valor de su ganado o cosecha, pero menos del 50% de los empresarios del sector agrícola están asegurados, lo que implica una gran pérdida potencial para aquellos sin cobertura.', '2025-02-05 20:12:21', '2025-02-05 20:12:21', NULL),
(53, 1, 1, 16, '2025-01-31', '9', 'Stock vacuno', 'El stock ganadero en general, y el de cría en particular, sigue sin recuperarse. El ritmo de ventas dependerá en gran medida de la evolución de las lluvias, con una seca que ya afecta a gran parte de las zonas criadoras.', '2025-02-05 20:12:21', '2025-02-05 20:12:21', NULL),
(54, 1, 1, 16, '2025-01-31', '42', 'Reservas de humedad', 'Sigue la sequía y los pronósticos no dan tregua: las reservas de humedad continúan muy estrechas, algunas zonas se beneficiaron con 60 milímetros.', '2025-02-05 20:12:21', '2025-02-05 20:12:21', NULL),
(55, 1, 1, 16, '2025-01-31', '18', 'Precios de fertilizantes', 'Los precios de los fosfatados continúan firmes. Los valores de referencia en Golfo, el FOB del PDA, alcanzan los 586 u$s/t, con una suba de 9 u$s/t. en el mes.', '2025-02-05 20:12:21', '2025-02-05 20:12:21', NULL),
(56, 1, 1, 16, '2025-01-31', '29', 'Relación de precio: agroquímicos - granos', 'A pesar de las bajas en los precios de los granos, particularmente en los valores de soja disponible, las relaciones de compra contra agroquímicos se mantienen positivas. ', '2025-02-05 20:12:21', '2025-02-05 20:12:21', NULL),
(57, 1, 1, 16, '2025-01-31', '27', 'Precios de agroquímicos', 'Durante todo 2024, los precios de los agroquímicos mostraron un comportamiento a la baja. Entre los principales encontramos al glifosato, que pasó de valer 7,4 u$s/lt en enero de 2024, a los actuales 4,4 u$s/lt, reflejando una retracción del 40% en los últimos 12 meses.', '2025-02-05 20:12:21', '2025-02-05 20:12:21', NULL),
(58, 1, 1, 16, '2025-01-31', '18', 'Demanda de fertilizantes', 'La demanda de fertilizantes en el mercado argentino permaneció prácticamente paralizada como resultado de la intensa sequía que afecta a gran parte de las zonas productivas del país. Este contexto climático crítico, sumado a la situación económica de los productores, desalienta cualquier tipo de anticipación de compras para la campaña fina 2025.', '2025-02-05 20:12:21', '2025-02-05 20:12:21', NULL),
(59, 1, 1, 16, '2025-01-31', '37', 'Retenciones: letra chica', 'Para acceder al beneficio se debe liquidar el 95% de las divisas de la mercadería a exportar, dentro de los 15 días hábiles de realizada la Declaración Jurada de Venta al Exterior (DJVE).', '2025-02-05 20:12:21', '2025-02-05 20:12:21', NULL),
(60, 1, 1, 16, '2025-01-31', '42', 'Pronóstico de clima', 'En un contexto de sequía en nuestro país, se esperan lluvias durante la primera semana de febrero que podrían aliviar el desarrollo de los cultivos.', '2025-02-05 20:12:21', '2025-02-05 20:12:21', NULL),
(61, 1, 1, 16, '2025-01-31', '21', 'Precios de granos', 'La soja cae desde el máximo alcanzado, presionada por expectativas de que la reducción de impuestos a las exportaciones en Argentina impulse su competitividad en el mercado global.', '2025-02-05 20:12:21', '2025-02-05 20:12:21', NULL),
(62, 1, 1, 16, '2025-02-10', '30', 'Importaciones', 'Esta semana se registró un nuevo ciclo de compras de MAP y DAP por parte de los importadores, un movimiento esperado por los traders, dado que hasta el momento ha habido pocos negocios destinados al abastecimiento para la siembra fina.', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(63, 1, 1, 16, '2025-02-11', '27', 'Nitrogenados', 'Luego de subas de precio de nitrogenados, desde principios de diciembre, durante la última semana el mercado de la urea mostró una tendencia bajista debido a la demora en la licitación de importación de India, la posibilidad de reactivación de la producción en Irán y el aumento de la oferta en Europa por menores costos del gas.', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(64, 1, 1, 16, '2025-02-18', '1', 'Demanda de insumos', 'Mejora la demada de insumos durante Febrero Vs. Enero 2025. Sobre todo insumos que vienen con aumentos de precios como algunos nitrogenados.', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(65, 1, 1, 16, '2025-02-13', '37', 'Fuerte señal de Caputo', 'Habrá tasas altas mientras sigue la negociación con el FMI para evitar presión cambiaria. El objetivo es mantener la demanda de pesos y que no haya dolarización de portafolios. Tampoco ayuda un clima internacional mucho más enrarecido, con fuertes caídas en Wall Street.', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(66, 1, 1, 16, '2025-02-14', '42', 'Zonas de sequía', 'Preocupan las pocas lluvias que  se registraron en  gran parte del NEA (Chaco principalmente), y algunas zonas del sur de Buenos Aires', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(67, 1, 1, 16, '2025-02-12', '29', 'Agroquímicos', 'La venta de agroqímicos esta frenada como suele suceder a esta altura de esta campaña, pero con mejoras respecto a las últimas semanas traccionado por las lluvias de Febrero. El productor busca pagos a cosecha con canje.  No existen créditos para capital de trabajo solamente para insumos por parte de la industria (muchos se ofrecen en dólares)', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(68, 1, 1, 16, '2025-02-15', '33', 'Estado de cultivos según planteo', 'En toda la zona central,  los cultivos de verano sembrados entre mediados de octubre y principios de noviembre, han sido los más afectados por el déficit hídrico y las altas temperaturas durante la floración.', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(69, 1, 1, 16, '2025-02-16', '14', 'Fosfatados', 'Desde mediados de 2024 el precio de fosfatados está estable en la plaza local. Durante las últimas jornadas, el mercado global de fosfatos tuvo precios al alza, impulsados por la demanda en India, Brasil y Estados Unidos, mientras que los suministros de China y Marruecos continúan afectando la oferta global.', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(70, 1, 1, 16, '2025-02-17', '11', 'Costos del Maíz', 'Los costos totales (directos e indirectos, sin computar el impuesto a las ganancias) para un planteo representativo para Zona Núcleo pueden estimarse en 1.222 US$/ha, levemente por debajo de los 1.233 US$/ha promedio en 2024 y de 1.287 US$/ha promedio de 2023. Esta baja responde a los menores precios de fertilizantes, semillas y agroquímicos.', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(71, 1, 1, 16, '2025-02-11', '42', 'Precios de herbicidas', 'Luego de alcanzar valores máximos en enero de 2022, el precio del glifosato muestra una tendencia a la baja en mercado local, desde entonces el precio perdió un 64% de valor. Otros herbicidas como glufosinato y 2,4D también acompañan la tendencia iniciada en 2022 (con bajas del 78%y 44%, respectivamente). ', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(72, 1, 1, 16, '2025-02-19', '24', 'Chicharrita', 'En el NOA, zona endémica, hubo un incremento de 18% de las localidades que capturaron más chicharritas. Lo positivo es que en el 80% los maíces se encontraban en estadios fenológicos avanzados (desde vegetativos tardíos hasta reproductivos), con lo cual ya superaron el período de susceptibilidad al complejo de achaparramiento del maíz, pero son los que mas sufrieron altas temperaturas y sequía , y van a rendir menos de la media.', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(73, 1, 1, 16, '2025-02-20', '8', 'Producción de Maíz mundial', 'En la última década la producción mundial de maíz ha aumentado más de 200 millones de toneladas, en términos de porcentaje se proyecta para la campaña 24/25 una producción 21% más grande que hace diez años atrás. Estados Unidos, Brasil y Argentina  producen casi la mitad del maíz del mundo se produce entre estos tres países, casi dos tercios es exportado desde ellos y consumen un tercio del maíz consumido en el mundo.', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(74, 2, 1, 16, '2025-02-11', '9', 'Realción Insumo:Producto', 'Baja la relación Insumo-Producto del Maíz:Novillo, tanto por baja de los precios de grano como por aumento del precio del novillo.', '2025-03-06 17:30:58', '2025-03-06 17:30:58', NULL),
(114, 1, 1, 16, '2025-03-10', '29', 'Precios de insumos', 'Luego de una larga tendencia a la baja se estabilizaron los precios de agroquímicos, a diferencia de los precios de  fertilizantes que están muy volátiles con tendencia al alza. Se esperan subas de precios de fosfatados y se dieron subas en nitrogenados. ', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(115, 1, 1, 16, '2025-03-11', '32', 'Precios de semillas', 'Baja de precios de semillas de Maíz por carry alto en la industria y buenos márgenes brutos para maíz temprano podrían traccionar un aumento en el área de maíz.', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(116, 1, 1, 16, '2025-03-12', '30', 'Importaciones', 'La mayoría de los importadores ya están confirmando sus embarques de fósforo. Una parte significativa del abastecimiento necesario para la campaña de fina ya está adquirida, pero a medida que se concreten más negocios, los precios tenderán a reflejar los nuevos costos', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(117, 1, 1, 16, '2025-03-13', '42', 'Exceso de lluvias', 'Aparece una amenaza para el maíz y complica la cosecha en la zona núcleo. La humedad ralentiza la recolección; se trilló el 23 % de la superficie y los rendimientos son dispares', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(118, 1, 1, 16, '2025-03-14', '1', 'Arrendamientos', 'Se comienza a hablar de arrendamientos tibiamente. Se espera que los valores de arrendamiento esten sostenidos o con leve alza en algunas regiones.', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(119, 1, 1, 16, '2025-03-15', '26', 'Campaña 2025/26', 'El incremento en las solicitudes de cotizaciones de insumos aumentó hacia el final del mes, aunque muchos de los negocios no se concretaron. Los productores están evaluando márgenes y comenzando a tomar el pulso del mercado, pero solo unos pocos se atreven a cerrar costos.', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(120, 2, 1, 16, '2025-03-16', '29', 'Demanda de insumos ', 'Por el momento no hay demanda  signigficativa para la gruesa. Para la fina comenzaron pedidos de algunos fertilizantes  y herbicidas, buscando de pagar a cosecha en muchos casos o con financiación buscando la mejor tasa y precio.  ', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(121, 2, 1, 16, '2025-03-17', '44', 'Campaña de fina ', 'El mercado de urea frenó parcialmente su tendencia bajista tras el esperado anuncio de India. Los precios de los insumos se encuentran bastante definidos/estables para la fina en general.', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(122, 2, 1, 16, '2025-03-18', '8', 'Stocks de maíz', 'Se espera que la relación stock/consumo mundial de maíz sea la más baja desde 2015, debido a la disminución de stocks.', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(123, 2, 1, 16, '2025-03-19', '14', 'Fosfatados ', 'El mercado de fosfatados mantuvo un tono firme, impulsado por una combinación de baja disponibilidad, aumentos en los costos de producción y actividad sostenida en Asia y América Latina', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(124, 2, 1, 16, '2025-03-13', '33', 'Trigo', 'Se estima que Rusia exportará menos Trigo que el cupo disponible, EEUU y Rusia atraviesan temperaturas muy bajas lo cual puede bajar la producción de trigo en estos importantes productores. Una normalización del clima y eventuales mejoras de precios pueden generar un buen ciclo de fina para la campaña 2025/26.', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(125, 2, 1, 16, '2025-03-30', '9', 'Ganadería', 'El precio del novillito, a moneda constante, es sólo un 9% inferior al máximo alcanzado tres años atrás.  Escasez de vacas y novillos. Precios para cuota Hilton historicamente altos. Baja la relación insumo-producto del maíz:novillo', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(126, 2, 1, 16, '2025-03-15', '24', 'Chicharrita', 'Al momento no se  ve una amenaza de chicharrita para la campaña  de maíz 2025/26. El vector se encuentra mucho mas controlado que la campaña anterior. ', '2025-04-08 16:43:31', '2025-04-08 16:43:31', NULL),
(127, 1, 1, 16, '2025-04-10', '17', 'Urea China', 'El mercado de urea de China continuó restringido por la política de limitación de exportaciones. No hubo señales claras de flexibilización de la política exportadora.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(128, 1, 1, 16, '2025-04-11', '27', 'Retenciones', 'El Gobierno ratificó el fin de la baja de retenciones y su intención de que el dólar se aproxime al piso de la banda y no al techo, mientras dure el actual esquema cambiario. ', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(129, 1, 1, 16, '2025-04-12', '29', 'Bayer-Glifosato', 'CEO de Bayer afirma que la empresa dejará de fabricar Roundup en “cuestión de meses”. Declara haber perdido entre 2 mil y 3 mil millones de dólares anuales dentro del negocio de glifosato.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(130, 1, 1, 16, '2025-04-13', '9', 'Oportunidad en Ganadería', 'En la ganadería los indicadores son tan buenos, que los criadores y los feedlots llevan meses de márgenes positivos y precios históricamente altos.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(131, 1, 1, 16, '2025-04-14', '29', 'Fosfatados', 'El mercado local de fosfatados continúa mostrando señales de firmeza, principalmente impulsado por la cercanía de la siembra fina y la limitada disponibilidad de productos, especialmente en fósforo.  ', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(132, 1, 1, 16, '2025-04-15', '1', 'Oferta de insumos', 'Si bien a nivel internacional no se registraron grandes movimientos de precios ni de actividad comercial, en Argentina la dificultad para asegurar oferta está provocando ajustes en los precios locales, tanto en urea como en fosfatados.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(133, 2, 1, 16, '2025-04-16', '26', 'Importaciones', 'En marzo se importaron 10 mil t. de DAP y 81 mil t. de MAP. Los acumulados muestran una fuerte recomposición en el inicio de la temporada de compras. De la mano del aumento de la superficie de cereales, la demanda de fosfatados se ve traccionada.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(134, 2, 1, 16, '2025-04-17', '34', 'Proyección de precios de soja', 'Por retenciones y dólar a $1.000, el campo proyecta que el valor de la tonelada caerá a $250.000. Por otro lado, la cosecha ya inició y los precios de los cultivos de verano comenzaron a bajar en la plaza local para posición mayo.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(135, 2, 1, 16, '2025-04-18', '14', 'Costos Vs. Tipo de cambio', 'El dólar oficial, anclado en la parte inferior de la banda de 1.000−1.400, no compensa los costos locales (fertilizantes +35% interanual, gasoil +50%). El margen neto por hectárea de soja es negativo en 4 de las 5 principales provincias productoras.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(136, 2, 1, 16, '2025-04-19', '35', 'Condiciones buscadas', 'El productor busca pagar los insumos a cosecha en pesos con bajas tasas.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(137, 2, 1, 16, '2025-04-13', '25', 'Alquileres', 'Se comienza a negociar más firmemente los alquileres que tienden a mantenerse sostenidos ( se escucha una leve tendencia al alza  (+1QQ ) en zona núcleo).', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(138, 2, 1, 16, '2025-04-30', '14', 'Costos ', 'Fletes: implican alrededor de 10% del costo total (4 a 12 % según zona), servicio de cosecha: 8% (las labores aumentaron compensada por baja en precios de los insumos), Insumos sacados en canje, en dólares, créditos bancario y tarjetas agro: 35%.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(139, 2, 1, 16, '2025-04-15', '30', 'Aprovisionamiento de Fósforo', 'La mayoría de los importadores ya están confirmando sus embarques de fósforo. Una parte significativa del abastecimiento necesario para la campaña de fina ya está adquirida, pero a medida que se concreten más negocios, los precios tenderán a reflejar los nuevos costos.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(140, 2, 1, 16, '2025-04-16', '27', 'Tasas ', 'La tasa de caución bursátil se ubica en el 26% anual, cayó notablemente e invita a tomar financiamiento en el mercado de capitales. Las tasas activas como adelantos en cuenta corriente están en el 40% anual, y los préstamos personales en el 69% anual.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(141, 2, 1, 16, '2025-04-17', '35', 'Nitrogenados', 'El mercado de nitrogenados mostró una tendencia a la suba impulsada por la demanda de los Estados Unidos y Europa, combinada con una oferta restringida en Medio Oriente y África del Norte y niveles de producción ajustados en Rusia. ', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(142, 2, 1, 16, '2025-04-18', '32', 'Semillas', 'Baja de precios de semillas de Maíz por carry alto en la industria y buenos márgenes brutos para maíz temprano podrían traccionar un aumento en el área de maíz.', '2025-05-07 17:28:09', '2025-05-07 17:28:09', NULL),
(143, 1, 1, 16, '2025-05-01', '29', 'Urea', 'El valor de la urea en el mercado local se ubica en torno a 520 u$s/tn, si bien los precios han aumentado en el último mes, este valor se ubica un 11% por debajo del promedio de 2024.', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(144, 2, 1, 16, '2025-05-30', '30', 'Negocios a la espera de cierre', 'A pesar de la buena expectativa de área a implantar, el volumen de negocios aún no refleja proporcionalmente ese potencial. No obstante, se espera que, conforme finalice la cosecha gruesa, la demanda de agroquímicos tome mayor impulso. ', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(145, 2, 1, 16, '2025-05-05', '14', 'Compras anticipadas', 'Con márgenes bajos en muchos cultivos y muchas zonas el productor no está apurado en comprar insumos para la gruesa, no ve un negocio en hacer comprar anticipadas grandes y de esa manera cubrirse del tipo de cambio como se hacía hace 1 año y medio.', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(146, 2, 1, 16, '2025-05-13', '30', 'Compras de fertilizantes', 'Con la siembra ya en marcha en algunas regiones y próxima a comenzar en otras, se observa una clara reactivación del mercado de fertilizantes, especialmente en el segmento de fosfatados.', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(147, 2, 1, 16, '2025-05-17', '27', 'Bajos márgenes para la industria', 'Actualmente, tanto los precios de fósforo como los de urea se mantienen por debajo de los niveles de reposición.', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(148, 1, 1, 16, '2025-05-07', '20', 'Cosecha Gruesa 24/25', 'Días muy favorables para recuperar el atraso de cosecha. La estabilidad atmosférica y los vientos del norte marcan el ritmo de una semana clave para las labores de cosecha de maices tardíos y de siembra de cereales de invierno.', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(149, 2, 1, 16, '2025-05-15', '44', 'Siembras de fina 25/26', 'Los pronósticos muestran muy pocas lluvias para los próximos 20 días, que ayudaria a secar los maíces tardíos y siembras de trigo y cebada.', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(150, 2, 1, 16, '2025-05-06', '42', 'Pronóstico mediano plazo', 'Se esperan lluvias normales  para Junio, Julio Agosto para  gran parte del sur y oeste agrícola y  lluvias levemente superior al promedio en el Litoral y NEA durante Agosto y septiembre', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(151, 2, 1, 16, '2025-05-01', '30', 'Formas de pago', 'Muchos productores buscan pagar los insumos a tasas bajas en dolares o factura con tipo de cambio abierto para evitar las altas tasas de financiación en pesos. ', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(152, 2, 1, 16, '2025-05-30', '14', 'Recaudación por retenciones', 'Se espera una recaudacion levemente inferior en USD en segundo semestre Vs. primer semestre por retenciones', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(153, 1, 1, 16, '2025-05-13', '26', 'Siembra de trigo y caminos', 'Muy buena humedad en capa arable del suelo para la siembra de trigo con excepción de Córdoba Centro-Norte que se encuentra con déficits hídricos. Por otra parte,  bajó el agua respecto a los máximos registrados de mayo en ciertas regiones de Buenos Aires, pero todavía se registran caminos y campos complicados.', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(154, 1, 1, 16, '2025-05-20', '8', 'Definición de rotaciones ', 'Algunas zonas aún registran excesos de agua en superficie,  por otro lado se registra mucha agua en profundidad ( y mejora de las Napas). Esto ocurre sumado a bajos márgenes de trigo, generando que el productor piense en no sembrar trigos de ciclo largo y pasar esos lotes a maíces tempranos en norte de Buenos Aires.', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(155, 2, 1, 16, '2025-05-21', '17', 'Márgenes de exportación', 'Los margenes de la exportacion de granos y de la distribución de agroquimicos está muy ajustada dada la baja en los precios de los commodities en general', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(156, 2, 1, 16, '2025-05-18', '16', 'Avance de ventas', 'Avance de ventas y entrega demorado respecto a campañas anteriores. Segun el segmento de insumo, el avance de varía entre 20 a 50 % de los presupuestado en ventas para los cultivos de verano.', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(157, 1, 1, 16, '2025-05-05', '32', 'Carry semillas', 'Baja de precios de semillas de Maíz por carry alto en la industria y buenos márgenes brutos para maíz temprano podrían traccionar un aumento en el área de maíz.', '2025-06-05 21:05:33', '2025-06-05 21:05:33', NULL),
(209, 2, 1, 16, '2025-06-01', '17', 'Importación de glifosato', 'En 2025 se registró un alto volumen de importación de glifosato granulado y una menor entrada de glifosato líquido de baja concentración.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(210, 1, 1, 16, '2025-06-30', '44', 'Siembras de trigo', 'El exceso de agua impidió la siembra de trigo de ciclo largo en amplias zonas de Buenos Aires, lo que llevó a los productores a optar por trigo de ciclo corto o maíz temprano.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(211, 1, 1, 16, '2025-06-06', '30', 'Ventas & despachos', 'Las ventas y entregas están demoradas respecto a campañas anteriores. Según el tipo de insumo, el avance de ventas para cultivos de verano varía entre el 30% y el 60% de lo presupuestado.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(212, 1, 1, 16, '2025-06-13', '14', 'Precios ', 'Fertilizantes: La urea subió de US$500 a US$570 por tonelada en pocos días debido al conflicto en Medio Oriente. Luego de los ataques más crudos estos valores se enfriaron.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(213, 1, 1, 16, '2025-06-17', '15', 'Márgenes ', 'Con márgenes bajos en muchos cultivos y regiones, los productores no están apurados en adquirir insumos para la campaña gruesa. Ya no consideran rentable realizar compras anticipadas para cubrirse del tipo de cambio, como ocurría hace un año y medio.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(214, 1, 1, 16, '2025-06-07', '31', 'Camelina', 'Gran interés por cultivos alternativos como la camelina y carinata dado que no tienen retenciones, son de ciclo más corto, con baja necesidad de insumos, margenes que ayudan al productor y a la sustentabilidad del ambiente.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(215, 2, 1, 16, '2025-06-15', '30', 'Ventas de insumos', 'Aunque hay buenas expectativas de superficie a sembrar, el volumen de negocios aún no refleja ese potencial. Se espera que la demanda de agroquímicos aumente llegado a la siembra de la campaña de cultivos de gruesa.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(216, 2, 1, 16, '2025-06-06', '14', 'Inversión de algunas empresas', 'Se percibe menos inversión por parte de las empresas en eventos del agro. Menor publicidad, menor cantidad de sponsors en un mercado que cada vez está más competitivo y con un productor que cada vez busca estar más informado.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(217, 2, 1, 16, '2025-06-01', '42', 'Lluvias', 'Se pronostican lluvias en julio para Buenos Aires, aunque persisten áreas con exceso de humedad que dificultan las labores y la logística en el campo.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(218, 1, 1, 16, '2025-06-30', '32', 'Semillas de maíz', 'La baja en el precio de semillas de maíz, producto del alto carry en la industria, junto con buenos márgenes brutos para maíz temprano, podrían impulsar un aumento en el área sembrada.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(219, 1, 1, 16, '2025-06-13', '42', 'Clima y definiciones', 'En Argentina, el invierno avanza con heladas generalizadas y lluvias escasas, afectando decisiones de siembra', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(220, 2, 1, 16, '2025-06-20', '14', 'Formas de pago', 'Muchos productores optan por pagar insumos en dólares a tasas bajas o con tipo de cambio abierto, para evitar las altas tasas de financiación en pesos.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(221, 1, 1, 16, '2025-06-21', '44', 'Rendimientos mundiales', 'El cambio climático sigue afectando los rendimientos: se estima una caída del 8% en la productividad global de cultivos hacia 2050, incluso con adaptación', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(222, 1, 1, 16, '2025-06-18', '42', 'Temperaturas en USA', 'En EE.UU., el calor y lluvias desparejas generan incertidumbre sobre el desarrollo de cultivos', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(223, 1, 1, 16, '2025-06-06', '17', 'Margenes por industria', 'Los márgenes de exportación de granos y distribución de agroquímicos están muy ajustados debido a la caída generalizada en los precios de los commodities.', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(224, 1, 1, 16, '2025-06-30', '27', 'Precios vs vecinos', 'El glifosato se ubica en torno a US$4,80/litro en promedio, mientras que la atrazina ronda los US$9,00/litro. En general, los herbicidas y fungicidas son entre un 5% y 11% más caros que en Brasil o Paraguay', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(225, 1, 1, 16, '2025-06-13', '26', 'Maquinaria y transporte', 'El costo de un tractor en Argentina es 27% más alto que en países vecinos. El flete granario (400 km) cuesta US$35,7/tonelada, un 23% más que el promedio regional', '2025-07-31 17:13:43', '2025-07-31 17:13:43', NULL),
(254, 1, 1, 16, '2025-07-30', '30', 'Avance de Ventas', 'Se registra un avance de un 60 % de ventas de semillas de maíz. Las ventas vienen muy demoradas dado que no existen incentivos financieros para anticipar compras y tampoco hay certidumbre impositiva ni climática.', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(255, 1, 1, 16, '2025-07-29', '26', 'Fijaciones de granos', 'Trigo: el 21% está comprometido y 15% con precio fijado, esto muestra relaciones de intercambio negativas (el precio del trigo no repuntó contra insumos más caros), aunque las posiciones a cosecha serían menos castigadas comparativame. Aun queda mucho trigo de la campaña anterior (disponible) por vender.', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(256, 1, 1, 16, '2025-07-28', '25', 'Precios de alquiler de la tierra', 'Alquileres agrícolas: no aflojan y se mantienen al mismo nivel del año pasado.  El costo promedio de un arrendamiento agrícola para la campaña 2025/26 se ubica en 11,5 quintales de soja por hectárea. Medido en dólares, por la baja de la soja, el precio es el menor en seis campañas.', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(257, 1, 1, 16, '2025-07-27', '42', 'Recarga de agua', 'Hasta el momento se vienen observando lluvias regulares y suficientes para garantizarnos una buena recarga de agua en el suelo en casi todas las zonas productivas pero conforme nos acerquemos a mitad de mes  lo que se conoce como “período crítico” para el trigo', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(258, 1, 1, 16, '2025-07-16', '43', 'Camelina: aumento de demanda', 'Gran demanda de Camelina en el exterior genera mucho interés en los productores por tener ciclos más cortos y muy baja demanda de agua del perfil.', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(259, 1, 1, 16, '2025-07-25', '30', 'Controversia en los precios', 'La soja subió y se acerca a los $400.000 en Rosario pese a las bajas externas. El mercado local tuvo una cotinuidad del rally alcista, en parte por el mayor tipo de cambio y necesidades locales a pesar que en Chicago la oleaginosa se encuentra en valores mínimos', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(260, 1, 1, 16, '2025-07-24', '6', 'Consumos de granos en ganadería', 'Gracias a los consumos internos estamos teniendo precios de maíz que están por encima de la paridad de exportación', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(261, 2, 1, 16, '2025-07-23', '42', 'Lluvias de Julio', 'Julio fue uno de los meses con más lluvias y es un elemento a considerar para la sanidad de la campaña fina. Aseguran que se adelantará la roya y se podría necesitar doble aplicación', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(262, 1, 1, 16, '2025-07-22', '27', 'Precios de exportadores', 'El sector exportador pagó sobreprecios (USD 179/t vs ~USD 168) para originar maíz y cumplir embarques, aunque aun así los despachos de julio cayeron 16% i.a.', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(263, 1, 1, 16, '2025-07-21', '14', 'Precios de insumos', 'Los costos de insumos agrícolas bajaron: urea -24%, fosfato diamónico -14%, glifosato -29% i.a., mejorando la relación insumo/producto y los márgenes de cultivos', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(264, 1, 1, 16, '2025-07-20', '44', 'Refertilización', 'Aprovechando la buena disponibilidad de humedad en el perfil, los productores están sumando kilos a las dosis de fertilizantes nitrogenados', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(265, 2, 1, 16, '2025-07-19', '11', 'Perspectivas de cambio de retenciones', 'Se proyecta que la baja de retenciones elevará la producción agropecuaria un +8% hacia 2035, inyectando US$ 28.800 millones extra en la próxima década.', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(266, 1, 1, 16, '2025-07-18', '21', 'Impactos de nuevas retenciones en soja', 'El precio de la soja disponible saltó de AR$ 345.000 a AR$ 385.000/tn (+12%) tras la rebaja de retenciones, sacando a la industria aceitera de números rojos y reactivando ventas de productores', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(267, 1, 1, 16, '2025-07-15', '14', 'Margenes & versatilidad', 'Los rendimientos y precios de la campaña ofrecen márgenes de maniobrabilidad muy acotados, conocer las herramientas comerciales tranquera afuera, así como los números tranquera adentro es lo que permitirá tomar decisiones más acertadas para elevar el precio promedio alcanzado y mejorar los márgenes de esta difícil campaña.', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(268, 1, 1, 16, '2025-07-14', '23', 'Maquinaria Agrícola', 'La industria nacional de maquinaria agrícola alertó una fuerte caída en ventas hacia mitad de año, atribuida a la baja rentabilidad del productor y la falta de crédito, y manifestó preocupación por la apertura a importaciones de equipos usados (eliminación del certificado CIBU), que pondría en jaque al sector local', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(269, 1, 1, 16, '2025-07-13', '4', 'Reactivación de Urea', 'El mercado local de urea muestra señales de reactivación: pese a precios elevados, esta semana se concretaron operaciones (incluso con despachos inmediatos), indicando que algunos compradores vuelven al mercado', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(270, 1, 1, 16, '2025-07-12', '3', 'Fertilizantes liquidos', 'Giro hacia fertilizantes líquidos: los productores están adoptando más fertilizantes líquidos, que ofrecen una mejor relación costo/nutriente que los sólidos, impulsando su demanda como alternativa más económica', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(271, 1, 1, 16, '2025-07-11', '27', 'Precios de Fosfatados', 'Precios de fosfatos distorsionados: los valores locales de MAP/DAP permanecen debajo del costo de reposición, creando una distorsión. Por ejemplo, MAP se cotiza ~US$805 en Argentina vs ~US$705 en Brasil (una brecha de ~$100 cuando históricamente era <US$10)', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(272, 1, 1, 16, '2025-07-10', '44', 'Arranque bueno para la fina', 'La zona núcleo recibió lluvias abundantes en julio, recargando suelos tras la sequía y asegurando humedad para un arranque excepcional del trigo', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(273, 1, 1, 16, '2025-07-09', '30', 'Demandas dispares por zona', 'Demanda dispar según la región (fosfatos): en India la demanda de DAP es sólida gracias al buen monzón y mayor siembra, mientras que Brasil muestra compras débiles de MAP debido a precios elevados y baja liquidez de los agricultores', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(274, 1, 1, 16, '2025-07-08', '14', 'Maíz y Costos', 'Mayor riesgo por costos altos: Aunque se prevén buenos márgenes, el mayor capital inmovilizado y el alza de costos aumentan el riesgo; se recomienda usar coberturas de precio en cuanto se confirmen costos elevados para asegurar los márgenes', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(275, 1, 1, 16, '2025-07-07', '18', 'Perspectivas de Urea', 'Urea con tendencia alcista global: El precio FOB Mar Negro alcanzó 488 US$/t (+13% vs junio) ante demanda estable; India planea una gran compra para agosto y en China se rumorea un impuesto a la exportación por los altos precios', '2025-08-08 15:24:21', '2025-08-08 15:24:21', NULL),
(276, 1, 1, 16, '2025-07-06', '27', 'Precios de fertilizantes', 'Precios internacionales de fertilizantes en alza: El fosfato diamónico (PDA) FOB Golfo subió a 612 US$/t (+2% vs junio) y el MAP (fosfato monoamónico) CFR Brasil a 755 US$/t (+11% vs junio)', '2025-08-08 15:24:22', '2025-08-08 15:24:22', NULL),
(277, 1, 1, 16, '2025-07-05', '3', 'Oferta de insumos', 'Oferta global de fertilizantes ajustada: las restricciones de exportación (por ejemplo, las cuotas vigentes en China) y la cautela ante eventos próximos (p.ej., una licitación de Bangladés para fosfatados) mantienen el mercado estable. Las variaciones de precios semana a semana han sido mínimas (generalmente inferiores al 2%), reflejando un equilibrio tenso entre oferta y demanda', '2025-08-08 15:24:22', '2025-08-08 15:24:22', NULL),
(278, 1, 1, 16, '2025-07-04', '11', 'Precios de insumos', 'En Norteamérica, los precios subieron notablemente ante compras anticipadas por la próxima temporada de aplicación otoñal y la incertidumbre sobre aranceles vigentes', '2025-08-08 15:24:22', '2025-08-08 15:24:22', NULL),
(279, 1, 1, 16, '2025-07-03', '18', 'Importaciones de Fertilizantes', 'Importaciones de MAP en auge local: Junio marcó el pico con 152 mil t importadas (acumulado 2021: 425 mil tn, récord vs 2019). El precio CIF junio fue 619 US$/t (+80 vs mayo) y el MAP doméstico cotizó ~840 US$/t (+90 US$ en el mes)', '2025-08-08 15:24:22', '2025-08-08 15:24:22', NULL),
(280, 2, 1, 16, '2025-07-17', '7', 'Cepo a empresas sigue sin cambios', 'Postergan la liberación del cepo para empresas. Aún no hay fechas de cese. Continúa sin cambios.', '2025-08-08 15:24:22', '2025-08-08 15:24:22', NULL),
(281, 1, 1, 16, '2025-07-26', '17', 'Importacion de Glifosato', 'En 2025 se registró un alto volumen de importación de glifosato granulado y una menor entrada de glifosato líquido de baja concentración.', '2025-08-08 15:24:22', '2025-08-08 15:24:22', NULL),
(282, 1, 1, 16, '2025-08-15', '18', 'Fertilizantes caros, margen en jaque', 'Aunque los precios internacionales de urea y MAP bajaron 1–4% en la última semana, los precios locales en Argentina subieron hasta 3%, mostrando desfasaje y oportunidad de arbitraje.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(283, 1, 1, 16, '2025-08-14', '11', 'El maíz sigue ganando la pulseada', 'El maíz mantiene la mejor relación insumo/producto del mercado, permitiendo comprar más fertilizantes, glifosato y gasoil por tonelada vendida que soja o trigo.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(284, 1, 1, 16, '2025-08-13', '42', 'Lluvias intensas complican la siembra', 'Las lluvias de Santa Rosa dejaron acumulados de hasta 140 mm en zonas agrícolas clave, complicando la siembra de gruesa y afectando la fina en áreas con suelos saturados.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(285, 1, 1, 16, '2025-08-12', '3', 'Glifosato en piso: ¿hora de comprar?', 'El glifosato cayó a $4,1/litro, el valor más bajo en más de dos años. Es un momento ideal para compras anticipadas y asegurar márgenes futuros.  Ventas de insumos muy demoradas 20 % menos Versus la campaña pasada. Herbicidas en general muy económicos.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(286, 1, 1, 16, '2025-08-11', '14', 'Gasoil por las nubes: presión de costos', 'El gasoil se mantiene en máximos relativos, superando $1,1/litro, lo que impacta fuertemente en los costos logísticos y de labores agrícolas. Fletes muy costosos se llevan un % más alto que el promedio de los ultimos 5 años.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(287, 1, 1, 16, '2025-08-10', '6', 'Novillo firme, vientres en alza', 'El precio del novillo mestizo supera los $3.200/kg, con una demanda firme. Los vientres suben por menor oferta y alta intención de retención.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(288, 2, 1, 16, '2025-08-09', '17', 'Carne argentina pierde terreno afuera', 'Las exportaciones de carne argentina pierden competitividad frente a Brasil por presión impositiva y costos internos, lo que exige una estrategia de largo plazo.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(289, 1, 1, 16, '2025-08-08', '30', 'Canje anticipado contra la volatilidad', 'Con insumos en baja y precios de granos estables, el canje anticipado se vuelve una herramienta clave para asegurar márgenes y reducir exposición a la volatilidad.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL);
INSERT INTO `insights` (`id`, `id_plan`, `status_id`, `id_user`, `date`, `icon`, `title`, `description`, `created_at`, `updated_at`, `deleted_at`) VALUES
(290, 2, 1, 16, '2025-08-08', '18', 'Urea y MAP: suben acá, bajan afuera', 'China liberó más de 600.000 toneladas de fosfatados al mercado, generando sobreoferta global y presión bajista en Asia, Brasil y parcialmente en Argentina.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(291, 1, 1, 16, '2025-08-06', '26', 'China inunda mercado de fosfatados', 'Brasil se posiciona como destino de equilibrio para el excedente de fertilizantes, aprovechando precios más bajos y reactivando compras tácticas.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(292, 1, 1, 16, '2025-08-05', '44', 'Brasil absorbe excedente global', 'La siembra de trigo y cebada avanzó  con demoras en zonas húmedas, pero con buenas perspectivas de superficie y expectativas de expansión en maíz. Actualmente ya se terminó de sembrar la fina', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(293, 2, 1, 16, '2025-08-15', '30', 'Trigo y cebada avanzan con cautela', 'Las importaciones de fertilizantes en Argentina crecieron 17,5% interanual, reflejando confianza en la campaña gruesa y necesidad de asegurar insumos clave.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(294, 1, 1, 16, '2025-08-14', '21', 'Exportaciones de fertilizantes en alza', 'El mercado de granos se mantiene estable, con soja en $285–290/TN, maíz cerca de $200/TN y trigo en $215–218/TN, sin señales claras de tendencia.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(295, 1, 1, 16, '2025-08-13', '4', 'Tecnología agro: del INTA al lote', 'El INTA y Expoagro impulsan la adopción de tecnologías 4.0, inteligencia artificial y robótica en el agro, con foco en eficiencia y competitividad.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(296, 2, 1, 16, '2025-08-12', '7', 'Año electoral: campo en defensiva', 'El año electoral genera incertidumbre en el agro, que enfrenta altos costos, precios internacionales debilitados y decisiones críticas de inversión.', '2025-09-04 22:59:03', '2025-09-04 22:59:03', NULL),
(297, 1, 1, 16, '2025-09-17', '30', 'Ventas agrícolas frenadas y preocupación', 'El avance de ventas agrícolas apenas alcanza el 70% de lo proyectado, mostrando un fuerte retraso respecto a la campaña pasada y generando preocupación en el sector.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(298, 1, 1, 16, '2025-09-26', '26', 'Empresas agropecuarias con stock mínimo', 'Las empresas del sector agropecuario operan con poco stock debido a la volatilidad de precios y los altos costos operativos, lo que obliga a ajustar estrategias de compra y logística.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(299, 1, 1, 16, '2025-09-15', '18', 'Fertilizantes líquidos pierden competitividad', 'Los fertilizantes líquidos no acompañaron la baja de la urea y pierden competitividad, aunque conservan ventajas agronómicas.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(300, 1, 1, 16, '2025-09-24', '7', 'Productores piden retenciones cero permanente', 'Productores reclaman que el régimen de retenciones cero se mantenga, temiendo caída de precios y liquidez si se revierte la medida.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(301, 1, 1, 16, '2025-09-13', '42', 'Emergencia agropecuaria por inundaciones', 'Las lluvias intensas provocaron emergencia agropecuaria en zonas bonaerenses, afectando la siembra y el estado de los cultivos.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(302, 2, 1, 16, '2025-09-18', '3', 'Precios de insumos: baja global, ajuste local', 'Aunque los precios internacionales de fertilizantes bajaron, en Argentina los valores se mantienen altos por escasez y logística.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(303, 1, 1, 16, '2025-09-26', '18', 'Urea baja afuera, escasea en Argentina', 'La urea bajó 1–4% en el mundo, pero la falta de producto y compras tardías impiden que la baja se traslade al mercado local.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(304, 1, 1, 16, '2025-09-23', '18', 'MAP y DAP: ofertas agresivas y poco stock', 'Las empresas ofrecen mezclas y MAP 10-50 con precios agresivos para liquidar inventarios, pero la disponibilidad es limitada.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(305, 1, 1, 16, '2025-09-30', '11', 'Tasas en pesos bajan, en dólares suben', 'Las tasas de financiamiento en pesos bajaron, pero las tasas en dólares subieron, complicando el acceso al crédito agropecuario.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(306, 2, 1, 16, '2025-09-29', '11', 'Relación insumo-producto mejora levemente', 'La relación insumo-producto mejora levemente, pero sigue desfavorable para trigo y maíz por precios internos y márgenes ajustados.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(307, 2, 1, 16, '2025-09-11', '14', 'Dólar sube, insumos importados más caros', 'El dólar oficial subió a $1.423,50, mejorando exportaciones pero encareciendo insumos importados y presionando los costos.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(308, 1, 1, 16, '2025-09-24', '3', 'Insumos estables', 'A pesar de la volatilidad internacional, los precios de insumos agrícolas se mantienen estables en el mercado local, lo que brinda previsibilidad .', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(309, 2, 1, 16, '2025-09-14', '6', 'Ganadería: retenciones cero hasta octubre', 'La ganadería mantiene retenciones cero hasta octubre, pero los feedlots siguen en rojo por el alto costo del maíz y márgenes negativos.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(310, 1, 1, 16, '2025-09-20', '17', 'China y Brasil, claves en exportación de granos', 'China aumentó compras de soja argentina y Brasil consolidó liderazgo exportador, desplazando a EE.UU. por la guerra comercial.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(311, 1, 1, 16, '2025-09-27', '42', 'Clima: lluvias récord y calor desafían la siembra', 'El clima extremo con lluvias récord y altas temperaturas desafía la siembra y el desarrollo de cultivos en varias regiones productivas.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(312, 1, 1, 16, '2025-09-24', '30', 'Ventas agrícolas aceleradas, luego frenadas', 'Las ventas agrícolas se aceleraron tras el anuncio de retenciones cero, pero luego se frenaron por incertidumbre y agotamiento de cupos.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(313, 1, 1, 16, '2025-09-13', '11', 'Salarios rurales suben, inflación presiona', 'Los salarios rurales subieron por paritarias, pero la inflación y el aumento de costos operativos presionan la rentabilidad del sector.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(314, 2, 1, 16, '2025-09-18', '4', 'Inversiones y fusiones sacuden el sector insumos', 'El sector de insumos vive un proceso de fusiones y adquisiciones, buscando eficiencia y escala ante la volatilidad de precios y demanda.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(315, 1, 1, 16, '2025-09-13', '14', 'Dólar volátil sacude decisiones del campo', 'El tipo de cambio bajó por la fuerte liquidación de divisas del agro, pero volvió a subir rápidamente por la demanda de dólares y la incertidumbre política que domina el mercado.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(316, 2, 1, 16, '2025-09-18', '14', 'Tasas opuestas complican el financiamiento', 'Las tasas de financiamiento en pesos bajaron, facilitando el acceso al crédito local, mientras que las tasas en dólares subieron y encarecen las operaciones internacionales.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(317, 1, 1, 16, '2025-09-19', '7', 'Retenciones cero: récord de dólares y polémica', 'La baja de retenciones generó una liquidación récord de divisas, pero también incertidumbre por reglas poco claras y cupos limitados.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(318, 1, 1, 16, '2025-09-28', '30', 'Cupo de ventas agotado en 72 horas', 'El cupo de ventas de granos se agotó en tres días, mostrando la presión de los productores por aprovechar el régimen transitorio.', '2025-10-06 14:14:40', '2025-10-06 14:14:40', NULL),
(343, 1, 1, 16, '2025-10-31', '26', 'Fertilizantes: calma y CFR en alza', 'Urea local estable y levemente al alza por firmeza global: CFR AR 440–445 US$/t. Actividad lenta y compras a compromiso; logística podría tensarse en nov–dic.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(344, 1, 1, 16, '2025-10-31', '18', 'MAP cede afuera, se plancha en Argentina', 'Fosfatados bajistas afuera; en Argentina el MAP ronda 745 US$/t (−1% semanal). Demanda fría y costos de azufre/energía limitan nuevos recortes.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(345, 1, 1, 16, '2025-10-31', '3', 'Urea firme por India y NOLA', 'El tender indio aceptó 430,7 kt y sostuvo la urea: NOLA a 390 $/st; Báltico y Egipto al alza; Brasil firme 420–430 CFR; China enfocada en mercado interno.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(346, 1, 1, 16, '2025-10-31', '11', 'Granos: Rosario con precios mixtos', 'Pizarra Rosario: soja $475.000, maíz $259.360 y trigo $264.365. Soja CBOT en 404 US$/t; señales mixtas sostienen ventas selectivas y coberturas.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(347, 1, 1, 16, '2025-10-28', '42', 'Niña al acecho y campos saturados', 'Perfiles cargados y ventanas de siembra cortas; riesgo de Niña en verano con calor extremo. Ajustar fechas, densidad e híbridos tolerantes.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(348, 1, 1, 16, '2025-10-28', '11', 'Trigo inicia cosecha y presiona valores', 'Interés externo tras mínimos de 5 años, pero la cosecha local ya presiona precios; conviene escalonar ventas y capturar premios por calidad.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(349, 2, 1, 16, '2025-10-31', '6', 'Ganado: novillo y vaca rompen techos', 'El novillo mestizo tocó 2,50 US$/kg vivo y la vaca marcó récord de $2.152/kg; el ‘dólar carne’ ajustó −3% en el mes, ordenando referencias.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(350, 1, 1, 16, '2025-10-22', '17', 'Retenciones cero: ventas adelantadas', 'La ventana de retenciones cero aceleró DJVE con liquidación del 90% en 3 días hábiles; alivio de caja de corto plazo y foco en timing.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(351, 1, 1, 16, '2025-10-31', '14', 'Dólares del agro se desploman en octubre', 'Tras finalizar el beneficio, la liquidación cayó a USD 1.117 M (−84% vs sep; −56% i.a.); noviembre suele ser el mes más bajo: monitorear flujos.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(352, 1, 1, 16, '2025-10-21', '30', 'VUCEA simplifica permisos de fertilizantes', 'ARCA integra ‘Aviso’ y ‘Autorización’ a VUCEA: menos papeles, validación automática y menor costo operativo para importadores del agro.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(353, 1, 1, 16, '2025-10-21', '30', 'SENASA baja costos de importación', 'Simplificación de registros y trazabilidad reduce el ‘costo argentino’ de la urea; integración TAD–VUCEA agiliza ingresos.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(354, 1, 1, 16, '2025-10-03', '4', 'Relación insumo/producto aún exigente', 'Fosfatos ceden pero la relación insumo–producto sigue alta y frena la demanda; la urea rebotó por licitación y reposición.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(355, 1, 1, 16, '2025-10-31', '18', 'Brasil tracciona CFR; oferta fluida', 'Brasil sostiene CFR de urea en 420–430 US$/t por siembra; oferta fluida desde Medio Oriente y Rusia, con importadores cautos.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(356, 1, 1, 16, '2025-10-31', '26', 'Logística: puertos tensos en noviembre', 'Se prevé presión en accesos portuarios por más traslados de grano; coordinar fletes con anticipación para asegurar abastecimiento de insumos.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(357, 1, 1, 16, '2025-10-27', '11', 'Soja Chicago firme; cautela local', 'Soja sostiene subas en Chicago por expectativas; localmente crecen ventas futuras. Usar puts/calls para capear volatilidad.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(358, 2, 1, 16, '2025-10-30', '30', 'Tras las legislativas, cautela en insumos', 'La cautela predomina tras las elecciones: pese a esperanzas de reactivación, el mercado de insumos sigue lento, frenado por la incertidumbre política y climática.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(359, 1, 1, 16, '2025-10-31', '42', 'Lluvias frenan tareas rurales', 'En varias regiones, las lluvias recientes dejaron zonas anegadas y caminos intransitables, deteniendo momentáneamente tanto las labores de campo como las compras de insumos agrícolas.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(360, 2, 1, 16, '2025-10-31', '26', 'Alerta logística: puertos al límite', 'La baja de retenciones a la soja desató ventas masivas; se proyecta fuerte flujo hacia puertos, lo que podría complicar la disponibilidad de camiones y obliga a coordinar la logística con anticipación.  Con fletes accesibles y precios sostenidos, se abre una ventana para mover granos ahora y capturar mejores precios netos en la venta.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(361, 2, 1, 16, '2025-10-30', '18', 'Fertilizantes: brecha global vs local', 'El precio internacional de fertilizantes como urea y MAP bajó hasta 4% en la última semana, pero en Argentina los valores subieron cerca de 3%, evidenciando desfasajes y oportunidad de arbitraje.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(362, 1, 1, 16, '2025-10-26', '3', 'Glifosato en alza: alerta de costos', 'El precio del glifosato en China subió un 18%, un encarecimiento que podría trasladarse pronto al mercado argentino e impactar en los costos de insumos para la próxima campaña agrícola.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(363, 1, 1, 16, '2025-10-27', '11', 'Trigo: mínimo global, cosecha local presiona', 'El precio internacional del trigo tocó un mínimo de 5 años, despertando interés comprador. La abundante oferta global y el inicio de la cosecha argentina están ejerciendo presión bajista sobre los precios locales.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(364, 1, 1, 16, '2025-10-10', '6', 'Novillo +67%: insumos más accesibles', 'La hacienda mejoró su poder de compra de insumos: entre septiembre de 2024 y septiembre de 2025 un índice de costos ganaderos subió 32%, mientras el precio del novillo aumentó 67%.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(365, 2, 1, 16, '2025-10-10', '6', 'China redefine importaciones: cautela local', 'China definirá en noviembre su nueva política de importación de carne vacuna. Los exportadores argentinos aguardan con cautela, dado que cualquier ajuste podría enfriar un mercado externo hoy muy firme.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(366, 1, 1, 16, '2025-10-20', '6', 'Cría: relación histórica, sin repunte', 'La relación ternero/novillo gordo es ~33% favorable al criador, una de las más altas en 24 años para noviembre. Aun con precios atractivos y buen clima, la recomposición del rodeo sigue sin despegar.', '2025-11-07 21:31:53', '2025-11-07 21:31:53', NULL),
(405, 1, 1, 16, '2025-11-27', '30', 'YPF sale del agro: Lartirigoyen en conversaciones', 'YPF inicia el desprendimiento de su negocio agroindustrial; Lartirigoyen & Cía. entre los interesados.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(406, 1, 1, 16, '2025-11-03', '21', 'Adecoagro se achica en siembra y apuesta a insumos', 'Adecoagro recorta siembra 21,8% y compra el 50% restante de Profertil, consolidando su integración vertical.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(407, 2, 1, 16, '2025-11-01', '26', 'Acuerdo GNL histórico: Argentina exportará 2 MT anuales', 'Argentina exportará 2 MTPA de GNL desde 2027 a SEFE, en un acuerdo de US$7.000 M con el buque Hilli Episeyo.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(408, 2, 1, 16, '2025-11-02', '21', 'Maíz temprano', 'Este año aumentó fuertemente el % de maíz temprano, sumado a que subio fuertemente el área de maíz. La industria con dudas acerca del área de maíz tardío  y el nivel de tecnologia dada la incertidumbre local.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(409, 2, 1, 16, '2025-11-05', '18', 'Fosfatos: costo vs. cereal por las nubes, mercado paralizado', 'MAP sin reacción pese a bajas globales; relaciones insumo/producto históricamente altas frenan la demanda.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(410, 1, 1, 16, '2025-11-05', '3', 'Nitrogenados: demanda mínima, solo compras puntuales', 'Urea y NPS con demanda acotada; productores compran solo para compromisos inmediatos.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(411, 1, 1, 16, '2025-11-04', '21', 'Trigo: rindes altos pero irregulares; siembra de soja/maíz lenta', 'Trigo con 34% cosechado y rendimientos altos pero variables; siembra de soja y maíz demorada por falta de piso.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(412, 1, 1, 16, '2025-11-26', '6', 'Hacienda por las nubes: valores récord en 20 años', 'Novillo +89% interanual; valores récord en 20 años; oferta limitada y demanda firme anticipan más subas.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(413, 2, 1, 16, '2025-11-01', '26', 'Trigo récord: retenciones 0 disparan exportaciones', 'Exportaciones de trigo se duplican en noviembre tras suspensión de retenciones; logística portuaria se activa.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(414, 1, 1, 16, '2025-11-06', '11', 'Soja firme: suspensión de retenciones sostiene precios', 'Soja mayo 2026 Rosario cotiza 80% del FOB; suspensión de retenciones sostiene precios internos.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(415, 2, 1, 16, '2025-11-05', '18', 'Fertilizantes: importadores apuran ventas por derrumbe externo', 'Importadores buscan cerrar el año con bajo carry ante bajas globales; presión por liquidar stock.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(416, 1, 1, 16, '2025-11-05', '18', 'Desfasaje: fertilizantes bajan 4% afuera y suben 3% aquí', 'Urea y MAP bajan 1–4% globalmente, pero en Argentina MAP se mantiene; oportunidad de arbitraje.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(417, 1, 1, 16, '2025-11-20', '7', 'Productores cautos: sin urgencias de compra ni venta', 'Sin urgencias de compra ni venta; decisiones postergadas por clima y precios inciertos.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(418, 1, 1, 16, '2025-11-05', '38', 'Maquinaria: patentamientos nov -13%; 2025 acumula +3%', 'Noviembre: -13,4% en patentamientos; acumulado 2025: +3,6% vs 2024.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(419, 1, 1, 16, '2025-11-27', '14', 'Dólar blue estable: respiro temporal para el agro', 'Dólar blue estable en ~$1460 a fines de noviembre; mejora previsibilidad de costos en el agro.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(420, 2, 1, 16, '2025-11-17', '42', 'Lluvias frenan trilla trigo', 'Frentes de tormenta traban la cosecha en núcleo; rendimientos altos (60–70 qq/ha), pero logística y pisos complican la salida de camiones.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(421, 2, 1, 16, '2025-11-16', '43', 'Paraquat arrasa: récord de ventas en insumos', 'El herbicida Paraquat fue la estrella de noviembre: se concretó un +50% de operaciones vs nov-2024, reflejando una fuerte demanda anticipada de herbicidas.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(422, 1, 1, 16, '2025-11-10', '14', 'Agroexportación en crisis: peor noviembre en 7 años', 'La liquidación agroexportadora de noviembre fue la más baja en 7 años: ingresaron US$760 M (-32% vs oct). Aun así, ene-nov 2025 acumuló US$30.324 M, un +24% vs 2024.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(423, 1, 1, 16, '2025-11-09', '38', 'Soja rinde más: comprar maquinaria cuesta 311 t menos', 'La suspensión de retenciones mejoró el poder de compra de la soja: en 2025 se necesitan 311 toneladas menos de soja que en 2024 para comprar una cosechadora nueva.', '2025-12-09 20:35:20', '2025-12-09 20:35:20', NULL),
(424, 1, 1, 16, '2025-12-05', '18', 'Activación del mercado de nitrógeno', 'El mercado de nitrógeno se activa fuertemente, especialmente en el sur de Buenos Aires, anticipando una campaña fuerte en enero. Confidencial: negociaciones cerradas y cotizaciones con actores clave.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(425, 1, 1, 16, '2025-12-08', '21', 'Perspectivas de campaña y uso de fertilizantes', 'Mercado cerca de 5 Mt, pero con 5 M ha inundadas se estiman 300–500 k t sin uso. Confidencial: planes internos de reasignación de stocks hacia la próxima campaña.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(426, 1, 1, 16, '2025-12-11', '26', 'Importaciones acumuladas y variaciones', 'Importaciones 2025: 4.004 t vs 3.387 t en 2024 (+18%). Urea +41%, UAN +3%, MAP +1%, Otros +18%. Confidencial: detalles de proveedores y tendencias ocultas del mercado.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(427, 1, 1, 16, '2025-12-15', '30', 'Impacto de licitación sorpresa de India', 'Licitación inesperada de India interrumpe la caída de precios y reintroduce firmeza. Confidencial: volúmenes adquiridos y nivel de stocks indios bajo reserva.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(428, 1, 1, 16, '2025-12-19', '18', 'Tensiones estructurales en fosfatados', 'Ausencia de exportaciones chinas hasta agosto 2026 y altos costos de azufre condicionan oferta, beneficiando MAP. Confidencial: estrategias internas de productores y reservas no divulgadas.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(429, 1, 1, 16, '2025-12-23', '3', 'Perspectiva América y Argentina', 'Brasil anticipa la safrinha; Argentina con demanda nula. Precios MAP y urea bajan ligeramente. Confidencial: estimaciones internas de recuperación y negociaciones estratégicas.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(430, 1, 1, 16, '2025-12-26', '21', 'Trigo abunda: 27,1 Mt sostienen presión de corto plazo', 'Cosecha al cerca del final y rinde promedio 42,9 qq/ha; oferta grande convive con actividad exportadora récord (IACA +3,5% m/m). ', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(431, 1, 1, 16, '2025-12-26', '21', 'Maíz 25/26: presión bajista', 'Competencia de EE.UU./Brasil firme; gran oferta en cosecha y ventas concentradas podrían aflojar disponible y basis.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(432, 1, 1, 16, '2025-12-26', '7', 'Brent cerca de USD 60', 'EEUU bloquea petroleros sancionados en Venezuela; Brent sube ~2–3% y ronda los USD 60; impacto moderado por superávit global.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(433, 2, 1, 16, '2025-12-26', '14', 'Bandas por inflación (ene)', 'El BCRA ajustará piso/techo de bandas por IPC desde enero (~2,5% según nov). Gobierno prevé habilitar giro de utilidades tras cierre de balances, hacia mitad de año.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(434, 1, 1, 16, '2025-12-26', '18', 'Fertilizantes: + demanda', 'Uso de fertilizantes: Se estima leve crecimiento del mercado 2025 vs 2024, traccionado por mayor área de maíz y algo más de dosis en núcleo y alrededores.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(435, 1, 1, 16, '2025-12-22', '6', 'Carne: menos volumen, más dólares; precios internos en máximos', 'Nov: embarques ‑5,4% m/m, pero mayor valor i.a.; novillo y terneros en máximos reales con oferta restringida. ', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(436, 1, 1, 16, '2025-12-23', '11', 'Maíz firme: mejora la relación insumo‑producto de fin de año', 'Soja estable y maíz +5,5% en 30 días; relaciones insumo‑producto mejoran en el margen para planteos tardíos.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(437, 1, 1, 16, '2025-12-26', '14', 'Campos en pausa activa: reformas en la mira sostienen consultas', 'Mercado rural con consultas sostenidas; alivio fiscal y medidas sobre DEX y liquidación anual fortalecen caja. ', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(438, 1, 1, 16, '2025-12-19', '6', 'Exportaciones de carne bajan en volumen', 'Exportaciones de carne en noviembre fueron 64,5 kt (-5,4 %), pero con fuerte suba interanual en valor', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(439, 1, 1, 16, '2025-12-23', '38', 'Tierra a la espera de reforma impositiva', 'Mercado de campos estable en noviembre, a la espera de reformas fiscales y laborales ', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(440, 1, 1, 16, '2025-12-26', '6', 'Haciendas en brecha récord', 'Informes indican oferta reducida y precios del novillo en gancho superan máximos históricos ', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(441, 2, 1, 16, '2025-12-05', '14', 'Sebos y expellers bajan', 'Precios domésticos de sebos y expellers ajustan a la baja en contexto de menor actividad y demanda selectiva.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(442, 2, 1, 16, '2025-12-07', '6', '¿Techo en precio global?', 'Analistas ven precios internacionales de carne cerca de máximos reales; oferta restringida y demanda externa en tensión.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(443, 2, 1, 16, '2025-12-05', '42', 'Cosecha: cuellos de botella', 'Lluvias y caminos frenan la trilla; productores buscan ventanas cortas para levantar y mover granos; la logística define tiempos y costos.', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(444, 1, 1, 16, '2025-12-26', '18', 'Importaciones', 'Importaciones de fertilizantes caen 3,6 %', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(445, 2, 1, 16, '2025-12-26', '18', 'Fertilizantes caen pero siguen altos', 'Costos de fertilizantes bajaron en octubre, aunque siguen 40–70 % encima de 2019', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(446, 1, 1, 16, '2025-12-26', '6', 'Ganado marca récord de precios en remates', 'Terneros 160–180 kg cotizan $5.526/kg, +19 % mes a mes, con valores en máximos históricos ', '2026-01-06 18:57:30', '2026-01-06 18:57:30', NULL),
(451, 1, 1, 16, '2026-01-29', '18', 'ACTIVACIÓN DEL MERCADO DE NITRÓGENO', '<p class=\"news__paragraph\">El mercado de nitrógeno se activa fuertemente, especialmente en el sur de Buenos Aires, anticipando una campaña fuerte en enero. Confidencial: negociaciones cerradas y cotizaciones con actores clave.</p>', '2026-01-29 22:10:29', '2026-01-29 22:10:29', NULL),
(452, 1, 1, 24, '2026-02-24', '3', 'Insight 1', '<p class=\"news__paragraph\">Texto Insight 1</p>', '2026-02-24 18:14:55', '2026-03-05 21:22:32', '2026-03-05 21:22:32'),
(453, 1, 1, 24, '2026-02-04', '8', 'Insight 2', '<p class=\"news__paragraph\">Texto insight 2</p>', '2026-02-24 18:15:15', '2026-03-05 21:22:22', '2026-03-05 21:22:22'),
(454, 1, 1, 44, '2026-02-23', '4', 'Bajos márgenes para Venta de fertilizantes', '<p class=\"news__paragraph\">La diferencia entre el precio en origen (FCA) y el precio puesto en destino (CFR) es muy  baja.</p><p class=\"news__paragraph\">En la práctica: cuesta casi lo mismo comprar el producto en el puerto de origen que recibirlo ya puesto en el puerto de destino, lo que indica fletes baratos o márgenes muy comprimidos.</p>', '2026-03-05 05:31:52', '2026-03-05 22:47:44', NULL),
(455, 1, 1, 44, '2026-02-27', '11', 'Precios de fertilizantes', '<p class=\"news__paragraph\">Los fertilizantes están lejos de sus valores más bajos, pero el mercado local sigue atrasado frente al internacional. Comprar ahora es una forma de cubrirse ante un ajuste pendiente y evitar tener que pagar más adelante por necesidad, que es siempre el escenario más costoso.</p>', '2026-03-05 05:32:27', '2026-03-05 05:32:27', NULL),
(456, 1, 1, 44, '2026-02-23', '15', 'Drones', '<p class=\"news__paragraph\">Los drones dejan de ser promesa y se consolidan como herramienta clave. Cada año se adopta crecientemente el uso de esta tecnología y la venta de drones buscando la eficiencia , reducción de costos , aumento de productividad y la sustentabilidad como eje</p>', '2026-03-05 05:34:15', '2026-03-05 05:35:28', NULL),
(457, 1, 1, 44, '2026-02-25', '37', 'Fuerte salto a la banca digital', '<p class=\"news__paragraph\">El 90% de las transacciones del agro pasaron por canales digitales, consolidando a la financiación bancaria como vía dominante. Muestra adopción masiva, eficiencia operativa y preferencia por procesos ágiles en el sector.</p>', '2026-03-05 05:37:40', '2026-03-05 05:39:50', NULL),
(458, 1, 1, 44, '2026-02-25', '35', 'Transacciones agrícolas en alza', '<p class=\"news__paragraph\">La financiación de insumos agrícolas mostró picos entre septiembre y diciembre, cuando se aceleran compras clave de campaña. La estacionalidad se mantiene, pero con un volumen general más alto que el año previo.</p>', '2026-03-05 05:39:25', '2026-03-05 05:39:25', NULL),
(459, 1, 1, 44, '2026-02-16', '31', 'Semillas lideran demanda', '<p class=\"news__paragraph\">Semillas fue el insumo más financiado, seguida por protección y nutrición. El productor prioriza asegurar el rendimiento del cultivo y la eficiencia productiva, incluso en contextos de incertidumbre macroeconómica.</p>', '2026-03-05 05:40:33', '2026-03-05 05:40:33', NULL),
(460, 1, 1, 44, '2026-02-05', '7', 'Crisis de insumos: Bioceres y Surcos en rojo', '<p class=\"news__paragraph\">La quiebra de Bioceres y los ajustes de Red Surcos, Agrofina y Los Grobo tensionan la cadena de agroinsumos: más riesgo de cortes de entrega, plazos de pago más cortos y prima de riesgo en financiamiento a distribuidores y productores medianos.</p>', '2026-03-05 22:40:51', '2026-03-05 22:40:51', NULL),
(461, 2, 1, 44, '2026-02-28', '4', 'Los Grobo–Agrofina: más ajuste y concentración', '<p class=\"news__paragraph\">Con Bioceres en convocatoria y quiebra, Surcos y Agrofina reestructurando y despidiendo personal, crece la concentración en manos de multinacionales y cooperativas grandes. El productor pierde poder de negociación y opciones tecnológicas de nicho en el corto plazo.</p>', '2026-03-05 22:41:45', '2026-03-05 22:41:45', NULL),
(462, 1, 1, 44, '2026-02-18', '15', 'Fertilizantes:  precios crecientes', '<p class=\"news__paragraph\">Los conflictos internacionales mantienen un piso alto y volátil para fertilizantes e insumos. Anticipar compras será clave para decidir cuándo tomar posición antes de nuevos shocks de precios.</p>', '2026-03-05 22:47:33', '2026-03-05 22:47:33', NULL),
(463, 1, 1, 44, '2026-02-23', '44', 'Trigo: rezagado con potencial de rebote', '<p class=\"news__paragraph\">El trigo corre detrás de maíz y cebada en precios, pero la proyección de caída productiva global y el riesgo climático del hemisferio norte le dan upside. Estrategia: defender trigo de buena calidad y priorizar ventas entre abril y julio.</p>', '2026-03-05 22:48:55', '2026-03-05 22:48:55', NULL),
(464, 2, 1, 44, '2026-02-25', '44', 'Cebada: sostén forrajero, venta táctica', '<p class=\"news__paragraph\">La cebada forrajera se sostiene por demanda externa firme, mientras la cervecera sufre por menor consumo. Con suba limitada en estos niveles, aparece más como cultivo para vender y financiar insumos que para correr el último peso de suba.</p>', '2026-03-05 22:49:30', '2026-03-05 22:49:30', NULL),
(465, 1, 1, 44, '2026-02-18', '34', 'Soja: fijar pisos en campaña 25/26', '<p class=\"news__paragraph\">Reafirmamos la idea de fijar parte de la soja estimada a precios actuales. En un escenario de costos altos y tipo de cambio incierto, asegurar un piso de soja permite ordenar la caja y la relación insumo/producto de la 26/27.</p>', '2026-03-05 22:50:45', '2026-03-05 22:50:45', NULL),
(466, 1, 1, 44, '2026-02-11', '36', 'Girasol: caja para insumos y combustible', '<p class=\"news__paragraph\">El girasol se consolida como uno de los mejores negocios de la 25/26. Usar ese resultado para compras tempranas de insumos y combustible de la 26/27 mejora la posición competitiva del productor frente a futuros aumentos y cuellos de oferta.</p>', '2026-03-05 22:51:16', '2026-03-05 22:51:16', NULL),
(467, 1, 1, 44, '2026-02-16', '43', 'Carne: capitalizar precios sin descuidar forraje', '<p class=\"news__paragraph\">La ganadería vive uno de sus mejores momentos, pero la falta de lluvias demora recrías y compromete verdeos. El desafío es capturar estos valores sin tensionar la oferta forrajera: ajustar cargas, tiempos de venta y planes de suplementación.</p>', '2026-03-05 22:53:01', '2026-03-05 22:54:20', NULL),
(468, 1, 1, 44, '2026-02-19', '6', 'Tambo: negocio fino, gestión gruesa', '<p class=\"news__paragraph\">Con el precio de la leche frenado, el tambo entra en zona compleja. La diferencia la marcarán eficiencia productiva (litros/ha, sólidos) y comercial (bonificaciones, logística, mix de destinos). Sin gestión fina, el margen se evapora pese a buenos volúmenes.</p>', '2026-03-05 22:53:37', '2026-03-05 22:53:37', NULL),
(469, 1, 1, 44, '2026-02-18', '28', 'Presupuesto 26/27: el momento más jugoso', '<p class=\"news__paragraph\">Los próximos 3 meses son clave: presupuestar 26/27 permite simular cómo combinaciones de precios, rindes, clima y costos redefinen el negocio. Es el momento ideal para usar planificación y control de gestión: inversiones, financiación, retiros y mix de actividades.</p>', '2026-03-05 22:55:38', '2026-03-05 22:55:38', NULL),
(470, 1, 1, 44, '2026-02-06', '9', 'Maíz + pasturas: oportunidad ganadera clave', '<p class=\"news__paragraph\">La actual relación fertilizante/maíz permite potenciar pasturas y verdeos a costos más competitivos, mejorando kilos por hectárea en recría y engorde. En un mundo donde los conflictos siguen encareciendo insumos, conviene adelantar compras, priorizar lotes de alto potencial y asegurar la oferta forrajera 26/27.</p>', '2026-03-05 23:45:53', '2026-03-05 23:45:53', NULL),
(471, 1, 1, 44, '2026-03-02', '4', 'Fertilizantes en llamas', '<p class=\"news__paragraph\">La nota la dan los fertilizantes: urea y fosfatados vuelan por la guerra en Medio Oriente; el conflicto se estira y la logística encarece fósforo y nitrógeno, elevando incertidumbre y volatilidad en la previa de la fina. </p>', '2026-04-07 23:56:59', '2026-04-08 00:03:06', NULL),
(472, 2, 1, 44, '2026-03-19', '7', 'Semáforo rojo: esperar', '<p class=\"news__paragraph\">Semáforo con muchos rojos: sugerimos postergar decisiones de compra/venta y enfocarse  en oportunidades (precio, financiación o logística) para no quedar expuesto a swings y recompras caras.</p>', '2026-04-07 23:58:53', '2026-04-08 00:02:48', NULL),
(473, 1, 1, 44, '2026-03-05', '11', 'Oleaginosas con ventaja', '<p class=\"news__paragraph\">Lo más favorable hoy está del lado de oleaginosas vs herbicidas y gasoil: el poder de compra mejora porque varios fitos no suben al ritmo de la energía, aunque el flete y la cosecha se encarecen. </p>', '2026-04-07 23:59:31', '2026-04-08 00:03:32', NULL),
(474, 1, 1, 44, '2026-03-11', '9', 'Hacienda toca un techo', '<p class=\"news__paragraph\">La hacienda parece haber encontrado techo este mes: gordo e invernada aflojan y el consumo no convalida; la corrección es selectiva, con sostén en lotes de mejor calidad y presión en categorías medias. [</p>', '2026-04-08 00:04:06', '2026-04-08 00:04:06', NULL),
(475, 1, 1, 44, '2026-03-08', '43', 'Recría resiste, pero aprieta', '<p class=\"news__paragraph\">Planteos de recría aún soportan el esquema forrajero, pero la suba de fertilizantes encarece el costo de pasto/silo y obliga a recalibrar cargas, suplementación y reposición para no licuar margen.</p>', '2026-04-08 00:05:05', '2026-04-08 00:05:05', NULL),
(476, 1, 1, 44, '2026-03-12', '9', 'Leche en USD deja de caer', '<p class=\"news__paragraph\">El precio de la leche en USD se estabiliza: el tipo de cambio más calmo y leves mejoras en pesos sostienen ingresos del tambo; la señal positiva existe, pero la brecha con industria y costos sigue apretando.</p>', '2026-04-08 00:05:29', '2026-04-08 00:05:29', NULL),
(477, 2, 1, 44, '2026-03-09', '10', 'Plan 26/27: lápiz fino', '<p class=\"news__paragraph\">En plena planificación 26/27: ajustar escenarios (rinde, precios, costos, fletes y financiación) porque campaña agrícola y tambera vienen con márgenes finos; el timing de insumos y coberturas será clave.</p>', '2026-04-08 00:06:07', '2026-04-08 00:06:07', NULL),
(478, 1, 1, 44, '2026-03-13', '3', 'Precio manda, no stock', '<p class=\"news__paragraph\">Abril mejora lo hídrico para fina, pero la demanda sigue fría; no se prevé falta general, sí riesgo de faltantes puntuales (MAP puro) y precios firmes por reposición cara.</p>', '2026-04-08 00:06:53', '2026-04-08 00:06:53', NULL),
(479, 1, 1, 44, '2026-03-31', '1', 'Urea+4% y MAP+3% en una semana', '<p class=\"news__paragraph\">Aun con baja rotación, los precios locales suben: urea FCA +4% (888→923) y MAP +3% (930→958) en una semana. Señal de mercado tenso: el “costo de esperar” puede ser pagar reposición más alta,</p>', '2026-04-08 00:07:47', '2026-04-08 00:07:47', NULL),
(480, 1, 1, 44, '2026-03-20', '11', 'Shock global y demanda cae', '<p class=\"news__paragraph\">Shock global por Ormuz: menos oferta y más volatilidad. El índice de “affordability” entra en negativo y puede profundizarse en 2026, forzando menor dosis, compras tardías o cambios hacia cultivos menos demandantes. </p>', '2026-04-08 00:08:33', '2026-04-08 00:08:33', NULL),
(481, 1, 1, 24, '2026-03-31', '8', 'Maíz: marzo récord de embarques', '<p class=\"news__paragraph\">Logística/export: marzo cerró con 3,7 Mt embarcadas de maíz y line-up 3,38 Mt al 31/3; mejora fuerte vs febrero y ordena el flujo de salida justo cuando el maíz temprano empieza a presionar cupos.</p>', '2026-04-08 00:11:15', '2026-04-08 15:12:50', NULL),
(482, 1, 1, 44, '2026-03-19', NULL, 'Trigo: 14 Mt sin precio', '<p class=\"news__paragraph\">Comercialización: todavía resta ponerle precio a ~14 Mt de trigo (cerca del 50%). Con la gruesa entrando, la estrategia pasa por escalonar fijaciones, cuidar almacenaje y evitar vender forzado por caja.</p>', '2026-04-08 01:06:08', '2026-04-08 01:06:08', NULL),
(483, 1, 1, 44, '2026-03-18', '19', 'Gasoil y flete suben 6–7%', '<p class=\"news__paragraph\">El conflicto ya encarece la cosecha: el gasoil local trepó y el flete sube 6–7%; el golpe es mayor lejos de puerto y castiga más al maíz por tonelada, estrechando márgenes regionales y decisiones de venta.</p>', '2026-04-08 01:07:10', '2026-04-08 01:07:10', NULL),
(484, 1, 1, 44, '2026-03-24', '13', 'Transporte en alerta', '<p class=\"news__paragraph\">Transportistas advierten que la escalada del gasoil en marzo tensiona tarifas y abastecimiento en plena cosecha; si no hay actualización de fletes, aumenta el riesgo de cuellos de botella y demoras en entregas.</p>', '2026-04-08 01:09:54', '2026-04-08 01:09:54', NULL),
(485, 1, 1, 3, '2026-03-30', NULL, 'FADA: el Estado se lleva 62,5%', '<p class=\"news__paragraph\">Índice FADA: el Estado captura 62,5% de la renta agrícola; sube por costos (urea/combustible) y tributos locales. El trigo aparece como el más golpeado: suben costos y la presión fiscal pesa más.</p>', '2026-04-08 01:10:13', '2026-04-08 21:16:32', NULL),
(486, 1, 1, 44, '2026-03-19', '4', 'Importaciones de fertilizantes al tope', '<p class=\"news__paragraph\">Argentina importó 4,1 Mt de fertilizantes en 2025 (2° mayor del siglo). La foto deja un riesgo: mayor dependencia externa justo cuando Medio Oriente y fletes agregan prima geopolítica al abastecimiento.</p>', '2026-04-08 01:10:45', '2026-04-08 01:10:45', NULL),
(487, 1, 1, 44, '2026-03-17', '25', 'Tecnología: menos N sin perder rinde', '<p class=\"news__paragraph\">INTA muestra que drones+algoritmos permiten ajustar dosis y reducir a más de la mitad el nitrógeno en girasol sin perder rendimiento; en un año de N caro, la eficiencia por ambiente gana valor económico inmediato.</p>', '2026-04-08 01:11:43', '2026-04-08 01:11:43', NULL),
(488, 1, 1, 44, '2026-03-27', '19', 'Menos maíz, más soja en 2026/27', '<p class=\"news__paragraph\">Con petróleo arriba y fertilizantes caros, crece el incentivo a migrar área hacia cultivos menos demandantes de N; el mercado ya descuenta más soja y menos maíz en 2026/27, con impacto en rotaciones y logística. </p>', '2026-04-08 01:13:17', '2026-04-08 01:13:17', NULL),
(489, 1, 1, 44, '2026-03-24', '6', 'Ganado: precios y señales mixtas', '<p class=\"news__paragraph\">Informe Ganadero muestra precios corrientes de gordo e invernada; tras los picos, aparecen señales de ajuste. Para decidir compras/ventas, mirar relación compra/venta y costo de alimentación (maíz/forraje). </p>', '2026-04-08 01:16:00', '2026-04-08 01:16:00', NULL),
(490, 1, 1, 44, '2026-03-19', '15', 'Crédito agro en USD y a 12 meses', '<p class=\"news__paragraph\">88% de operaciones en USD y 60% a 12 meses; además crecen créditos garantizados con granos (520 mil t) y precio a fijar. Con márgenes ajustados, calzar vencimientos con cosecha es central.</p>', '2026-04-08 01:16:33', '2026-04-08 01:16:33', NULL);
